var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"허신들이… 사라지기 시작했어……!","JPN":"虚神たちが……消え始めた……！","ENG":"The Hollow Gods...! They're disappearing...!","TWN":"虛神……開始消失了！"},"stage":{"bg":"COUNTERSIDE_GRAY","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그뿐만이 아니야… 런던의 거리도, 건물도 그리고 사람들까지 전부 사라졌어……!","JPN":"それだけじゃない……ロンドンの街も、建物も。それに人々まで、全部消えた……！","ENG":"And not just that... The streets of London, the buildings, and even the people are all vanishing...!","TWN":"不僅如此……倫敦的街道、建築，甚至人們全都消失了！"},"stage":{"bg":"COUNTERSIDE_GRAY","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그럼, 유미나가 성공했다는 뜻인가……?","JPN":"じゃあ、ミナが成功したってこと……？","ENG":"Then that means... Yoo Mina succeeded...?","TWN":"劉米娜成功了嗎？"},"stage":{"bg":"COUNTERSIDE_GRAY","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어이, 검은 갑옷…? 너……?","JPN":"おい、黒い鎧……？　あんた……？","ENG":"Hey, black armor...? Are you...?","TWN":"喂，黑色盔甲？你？"},"stage":{"bg":"COUNTERSIDE_GRAY","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그렇군. 나 또한 거짓된 세계의 잔재였을 뿐이니…….","JPN":"そうか。我もまた、偽りの世界の残滓に過ぎなかったと……","ENG":"I see. I, too, was merely a remnant of this false world...","TWN":"原來如此。我也不過是虛假世界的殘餘……"},"stage":{"bg":"COUNTERSIDE_GRAY","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"소멸하는 세계가 내 존재마저 지워버리는구나. 찰나의 인연이었지만, 무운을 빌겠다.","JPN":"消滅する世界が、我の存在さえ消し去ってゆく。刹那の縁であったが、武運を祈ろう。","ENG":"And now that this world is fading, it erases my very existence. It was a fleeting bond, but I wish you fortune.","TWN":"消逝的世界連我的存在也要抹去。雖然只是短暫的緣分，但願你好運。"},"stage":{"bg":"COUNTERSIDE_GRAY","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"다른 세계의 이방인들이여…….","JPN":"異世界の異邦人たちよ……","ENG":"Outsiders from another world...","TWN":"其他世界的陌生人們……"},"stage":{"bg":"COUNTERSIDE_GRAY","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"라이카, 눈 좀 떠 봐요!","JPN":"ライカ、目を開けて！","ENG":"Laika, open your eyes!","TWN":"萊卡，快睜開眼睛！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"미나 씨가 해냈어요! 이제 거의 끝났다고요……!","JPN":"ミナさんがやってくれたの！　もうほぼ終わったよ……！","ENG":"Mina did it! It's almost over now...!","TWN":"米娜成功了！現在幾乎要結束了……!！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"조금만 더… 조금만 더 버티면……","JPN":"あと少し……少しだけ耐えれば……","ENG":"Just a little more... hang in there a little longer...","TWN":"再多堅持一會兒……再多堅持一會兒的話……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"으음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"이건, 신성 반응이잖아……?","JPN":"これは、神聖反応……？","ENG":"This is a Divinity response...","TWN":"這是，神聖反應啊？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"미약하지만… 틀림없이 일정한 패턴으로 반응하고 있어…….","JPN":"微弱だけど……確かに一定のパターンで反応している……","ENG":"It's faint... but the pattern is responding in a regular fashion...","TWN":"雖然微弱……但確實在以一定的模式反應……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"하지만 허신은 전부 사라졌을 텐데, 어째서……?","JPN":"でも虚神は全て消えたはずなんじゃ……？　どうして……？","ENG":"But all the Hollow Gods should be gone. So why...?","TWN":"但是所有的虛神都應該消失了，為什麼？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_QM","text":{"KOREA":"그렇군…….","JPN":"そうか……","ENG":"I see...","TWN":"原來如此……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_QM","text":{"KOREA":"이 풍경이 멸망해 버린 우리 세계의 원래 모습인가……?","JPN":"この光景が、滅亡してしまった私たちの世界の本当の姿か……？","ENG":"So this is what the world we lost originally looked like in ruin...","TWN":"這景象是我們那個已毀滅世界的原本模樣嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"당신은……?","JPN":"あなたは……？","ENG":"Who are you...?","TWN":"你是？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"결국에는 아무것도 없는 황무지라니…….","JPN":"結局は何一つ存在しない荒地とは……","ENG":"In the end, it's just a wasteland...","TWN":"結果竟然是片荒蕪之地……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"참으로 덧없군. 이 세계를 구하기 위해, 파트너와 나는 고군분투해왔는데 말이지…….","JPN":"儚いな。この世界を救おうと、私とパートナーはあれほど必死に動いていたというのに……","ENG":"How fleeting. My partner and I struggled so hard to save this world...","TWN":"真是無常啊。為了拯救這個世界，我和夥伴一直在努力奮鬥……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 이게 이 세계의 진실이라면, 결국 마주할 수밖에 없을지도 모르지.","JPN":"しかしこれがこの世界の真実というのならば、いずれは向き合うしかないのだろう。","ENG":"But if this is the truth of it, maybe it's something we had to face all along.","TWN":"但如果這是這個世界的真相，最終可能不得不面對。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"잠깐만요, 당신 몸이……?","JPN":"ちょっと待ってください、あなた、体が……？","ENG":"Wait, your body...!","TWN":"等等，你的身體？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 알고 있네.","JPN":"ふふ、わかっているさ。","ENG":"Haha, I know.","TWN":"呵呵，我知道。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이래서야 움직이기 쉽지 않겠군.","JPN":"これだと、思うように動くことは出来そうにないな。","ENG":"It's getting hard to move like this...","TWN":"這樣一來就不容易行動了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"미안하지만, 꼬마 레이디. 에스코트를 부탁할 수 있겠나?","JPN":"すまないが、リトルレディー。エスコートを頼めるかね？","ENG":"Sorry, little lady. Mind giving me a hand?","TWN":"抱歉，小姐。我可以請求護送嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};